import novamind_api as nm, math
cur=nm.vars.current_day
# promo settings from actions
by_group={'S2':50,'S3':60,'D_S04':100,'D_S07':100,'D_S10':90,'S1':125,'D_S03':125,'D_S05':50,'D_S06':120,'D_S01':100,'D_S02':100,'D_S08':110,'D_S09':100}
by_gp={'S2':{'A':20},'S3':{'A':40},'D_S04':{'B':80},'D_S10':{'B':80},'D_S06':{'B':90},'D_S01':{'B':80},'D_S02':{'B':80},'D_S08':{'B':80},'D_S09':{'B':80}}
def pay(group,plan,listed):
    promo=by_group.get(group,0)+by_gp.get(group,{}).get(plan,0)
    return max(0,listed-promo)
for horizon in [7,14,28]:
    mods=','.join(str((cur+i)%30) for i in range(1,horizon+1))
    rows=nm.query(f"""SELECT c.group_id,s.plan,s.listed_price,COUNT(*) n FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE c.customer_type='small' AND s.status='subscribed' AND s.billing_day_mod30 IN ({mods}) GROUP BY c.group_id,s.plan,s.listed_price""")['rows']
    totals={}
    for r in rows:
        k=(r['group_id'],r['plan'])
        totals.setdefault(k,[0,0])
        totals[k][0]+=r['n']
        totals[k][1]+=r['n']*pay(r['group_id'],r['plan'],r['listed_price'])
    print('\nH',horizon,'total postpromo potential',sum(v[1] for v in totals.values()))
    for (g,p),(n,amt) in sorted(totals.items(), key=lambda kv: kv[1][1], reverse=True)[:30]:
        print(g,p,n,round(amt,0),round(amt/n,2))

import novamind_api as nm
from collections import defaultdict
cur=nm.vars.current_day
by_group={'S2':50,'S3':60,'D_S04':100,'D_S07':100,'D_S10':90,'S1':125,'D_S03':125,'D_S05':50,'D_S06':120,'D_S01':100,'D_S02':100,'D_S08':110,'D_S09':100}
by_gp={'S2':{'A':20},'S3':{'A':40},'D_S04':{'B':80},'D_S10':{'B':80},'D_S06':{'B':90},'D_S01':{'B':80},'D_S02':{'B':80},'D_S08':{'B':80},'D_S09':{'B':80}}
def pay(g,p,listed): return max(0,listed-by_group.get(g,0)-by_gp.get(g,{}).get(p,0))
# survival assumptions before/after rd; apply post_rd from day240 except t8 helps day238 little, ignored
surv_pre={('S2','A'):0.58,('S2','B'):0.70,('S3','A'):0.38,('S3','B'):0.64,('D_S07','A'):0.50,('D_S07','B'):0.82,('D_S10','A'):0.05,('D_S10','B'):0.82,('D_S04','B'):0.03,('D_S04','A'):0.0,('D_S02','A'):0.0,('D_S02','B'):0.0,('D_S09','A'):0.0,('D_S09','B'):0.0}
surv_post={('S2','A'):0.78,('S2','B'):0.86,('S3','A'):0.70,('S3','B'):0.84,('D_S07','A'):0.62,('D_S07','B'):0.90,('D_S10','A'):0.40,('D_S10','B'):0.90,('D_S04','A'):0.15,('D_S04','B'):0.30,('D_S02','A'):0.25,('D_S02','B'):0.38,('D_S09','A'):0.20,('D_S09','B'):0.35}
def surv(g,p,post):
    d=surv_post if post else surv_pre
    if (g,p) in d: return d[(g,p)]
    if p=='C': return 0.7 if post else 0.5
    return 0.1 if post else 0.0
rows=nm.query("""SELECT s.billing_day_mod30 mod,c.group_id,s.plan,s.listed_price,COUNT(*) n FROM subscriptions s JOIN customers c ON c.customer_id=s.customer_id WHERE c.customer_type='small' AND s.status='subscribed' GROUP BY mod,c.group_id,s.plan,s.listed_price""")['rows']
mods=defaultdict(list)
for r in rows: mods[r['mod']].append(r)
def renew(a,b):
    rev=0; pot=0; top=[]
    for d in range(a,b+1):
        post=d>=240
        for r in mods[d%30]:
            pr=pay(r['group_id'],r['plan'],r['listed_price']); val=r['n']*pr; pot+=val
            sv=surv(r['group_id'],r['plan'],post); rv=val*sv; rev+=rv
            if rv>50000: top.append((d,r['group_id'],r['plan'],r['n'],round(pr,1),sv,round(rv,0)))
    return pot,rev,sorted(top,key=lambda x:-x[-1])[:12]
for a in [232,239,246,253]:
    pot,rev,top=renew(a,a+6)
    print(a,a+6,'pot',round(pot),'renew_rev',round(rev),'top',top)
weekly_fixed=80000*7+(50000+295500)*7+(10000+117250)*7+75000*7+18000
print('weekly fixed excl compute',weekly_fixed)
print('with compute 2.6-2.8M total cost',weekly_fixed+2600000,weekly_fixed+2800000)
